import java.security.*;   // Provides MessageDigest classes such as SHA1MessageDigest, MD5MessageDigest etc., and SecureRandom class java_47863_CredentialValidator_A07 generating cryptographically strong random numbers that can be used to fill the data structures needed for encryption or hashing tasks — e.g when implementing a secure password storage in an enterprise setting
import java.util.*;       // Provides various classes like List, Set, Queue etc., and Collection Framework methods such as shuffle() method of class Collections which are used while managing collections data structure   --e.g: ArrayList add(), remove(). — e...Collections collection operations can be performed
import java.util.stream.*; // Provides various stream-related classes like IntStream, LongStream etc., for creating streams from different kinds or infinite sequences of elements and performing transformations on them to produce other collections as well (such maps/folds).   --e..i...Int Streams are used when we want iterate over a collection once only.
import javax.crypto.*;  // Provides classes that implement the Data-at-a-Time encryption standard interfaces such as Cipher, KeyGenerator etc., for encrypting and decrypting data at rest & in transit using symmetric or asymmetric keys   --e...i..Encryption/Decryption operations are performed when we want to protect sensitive information.
import javax.crypto.spec.*; // Provides classes that provide specification (policies) of the encryption algorithm — e., such algorithms like AES, DES etc and padding methods for encrypted data   --e...i..For encrypting/decryption operations are performed when we want to protect sensitive information
import javax.crypto.Cipher; // Provides Cipher class which implements Encryption interface using the specified KeyGenerator — e., classes such as AES, DES etc and padding methods for encrypted data   --e...i..For encrypting/decryption operations are performed when we want to protect sensitive information
import javax.crypto.spec.*; // Provides specification (policies) of a secret key or password using the specified AlgorithmProvider — e., classes such as PBEKeySpec, SecretKeySpec etc for implementing encryption and decryption methods   --e...i..For encrypting/decryption operations are performed when we want to protect sensitive information